// src/pages/ExpensesPage.js
import React, { useState, useEffect } from "react";
import { useApp } from "../context/AppContext";
import { expenseAPI } from "../utils/api";
import ExpenseModal from "../components/modals/ExpenseModal";
import DeleteModal from "../components/modals/DeleteModal";
import toast from "react-hot-toast";
import { formatDate } from "../utils/khmerUtils";

const CATEGORIES = [
  "food",
  "drink",
  "fruit",
  "transport",
  "clothing",
  "health",
  "entertainment",
  "education",
  "utilities",
  "shopping",
  "other",
];
const MONTHS_EN = [
  "January",
  "February",
  "March",
  "April",
  "May",
  "June",
  "July",
  "August",
  "September",
  "October",
  "November",
  "December",
];

export default function ExpensesPage() {
  const { t, formatAmount, formatNum, language } = useApp();
  const [expenses, setExpenses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [addModal, setAddModal] = useState(false);
  const [editData, setEditData] = useState(null);
  const [deleteId, setDeleteId] = useState(null);
  const [deleting, setDeleting] = useState(false);
  const [filterCat, setFilterCat] = useState("");
  const [filterMonth, setFilterMonth] = useState("");
  const [filterYear, setFilterYear] = useState("");
  const [search, setSearch] = useState("");

  const loadExpenses = async () => {
    setLoading(true);
    try {
      const params = {};
      if (filterCat) params.category = filterCat;
      if (filterMonth && filterYear) {
        params.month = filterMonth;
        params.year = filterYear;
      } else if (filterYear) params.year = filterYear;
      const res = await expenseAPI.getAll(params);
      setExpenses(res.data || []);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadExpenses();
  }, [filterCat, filterMonth, filterYear]);

  const handleDelete = async () => {
    setDeleting(true);
    try {
      await expenseAPI.delete(deleteId);
      toast.success(t("deletedSuccess"));
      setDeleteId(null);
      loadExpenses();
    } catch (err) {
      toast.error(err.message);
    } finally {
      setDeleting(false);
    }
  };

  const filtered = expenses.filter(
    (e) => !search || e.itemName?.toLowerCase().includes(search.toLowerCase()),
  );

  const totalUSD = filtered.reduce((s, e) => s + (e.amountUSD || 0), 0);

  const [viewMode, setViewMode] = useState("table");

  return (
    <div className="space-y-5 animate-fade-in">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1
            className="font-display font-bold text-2xl"
            style={{ color: "var(--text-primary)" }}
          >
            💸 {t("expenses")}
          </h1>
          <p
            className="text-sm mt-0.5"
            style={{ color: "var(--text-secondary)" }}
          >
            {t("total")}: {formatAmount(totalUSD)} ·{" "}
            {formatNum(filtered.length)} {t("items")}
          </p>
        </div>
        <button
          className="btn btn-primary"
          onClick={() => {
            setEditData(null);
            setAddModal(true);
          }}
        >
          + {t("addNew")}
        </button>
      </div>

      {/* Filters */}
      <div className="card p-4">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
          <input
            type="text"
            placeholder={t("search")}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="form-input"
          />
          <select
            value={filterCat}
            onChange={(e) => setFilterCat(e.target.value)}
            className="form-input"
          >
            <option value="">{t("allCategories")}</option>
            {CATEGORIES.map((c) => (
              <option key={c} value={c}>
                {t(c)}
              </option>
            ))}
          </select>
          <select
            value={filterMonth}
            onChange={(e) => setFilterMonth(e.target.value)}
            className="form-input"
          >
            <option value="">{t("allMonths")}</option>
            {MONTHS_EN.map((m, i) => (
              <option key={m} value={i + 1}>
                {m}
              </option>
            ))}
          </select>
          <select
            value={filterYear}
            onChange={(e) => setFilterYear(e.target.value)}
            className="form-input"
          >
            <option value="">All Years</option>
            {[2024, 2025, 2026, 2027, 2028].map((y) => (
              <option key={y} value={y}>
                {y}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* Table */}
      <div className="card overflow-hidden">
        {loading ? (
          <div
            className="p-8 text-center text-sm"
            style={{ color: "var(--text-secondary)" }}
          >
            {t("loading")}
          </div>
        ) : filtered.length === 0 ? (
          <div className="p-12 text-center">
            <div className="text-4xl mb-3">🧾</div>
            <div
              className="font-semibold"
              style={{ color: "var(--text-secondary)" }}
            >
              {t("noExpenses")}
            </div>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr
                  style={{
                    background: "var(--bg-primary)",
                    borderBottom: "1px solid var(--border)",
                  }}
                >
                  {[
                    "",
                    t("itemName"),
                    t("category"),
                    t("amount"),
                    t("date"),
                    t("paymentMethod"),
                    t("quantity"),
                    "",
                  ].map((h, i) => (
                    <th
                      key={i}
                      className="px-4 py-3 text-left text-xs font-bold uppercase tracking-wide"
                      style={{ color: "var(--text-secondary)" }}
                    >
                      {h}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {filtered.map((e, idx) => (
                  <tr
                    key={e._id}
                    className="transition-colors hover:bg-opacity-50"
                    style={{
                      borderBottom: "1px solid var(--border)",
                      background:
                        idx % 2 === 0 ? "transparent" : "var(--bg-primary)",
                    }}
                  >
                    <td className="px-4 py-3 text-xl">{e.categoryEmoji}</td>
                    <td className="px-4 py-3">
                      <div
                        className="font-semibold text-sm"
                        style={{ color: "var(--text-primary)" }}
                      >
                        {e.itemName}
                      </div>
                      {e.noted && (
                        <div
                          className="text-xs mt-0.5 truncate max-w-xs"
                          style={{ color: "var(--text-secondary)" }}
                        >
                          {e.noted}
                        </div>
                      )}
                    </td>
                    <td className="px-4 py-3">
                      <span className="badge badge-planned">
                        {t(e.category)}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <div
                        className="font-bold text-sm"
                        style={{ color: "#0ea5e9" }}
                      >
                        {formatAmount(e.amountUSD, e.amountKHR)}
                      </div>
                      <div
                        className="text-xs"
                        style={{ color: "var(--text-secondary)" }}
                      >
                        {e.currency === "KHR"
                          ? `${e.amount?.toLocaleString()} ៛`
                          : `$${e.amount}`}
                      </div>
                    </td>
                    <td
                      className="px-4 py-3 text-sm"
                      style={{ color: "var(--text-secondary)" }}
                    >
                      {formatDate(e.date, language, "medium")}
                    </td>
                    <td className="px-4 py-3">
                      <span
                        className={`badge ${e.paymentMethod === "qr" ? "badge-completed" : "badge-planned"}`}
                      >
                        {e.paymentMethod === "qr"
                          ? "📱"
                          : e.paymentMethod === "cash"
                            ? "💵"
                            : e.paymentMethod === "card"
                              ? "💳"
                              : "🔄"}{" "}
                        {t(e.paymentMethod)}
                      </span>
                      {e.imageQr && (
                        <div className="mt-1">
                          <img
                            src={e.imageQr}
                            alt="QR"
                            className="w-8 h-8 rounded object-cover"
                          />
                        </div>
                      )}
                    </td>
                    <td
                      className="px-4 py-3 text-sm text-center"
                      style={{ color: "var(--text-secondary)" }}
                    >
                      {e.quantity}
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex gap-1">
                        <button
                          className="btn btn-ghost p-2 text-sm"
                          onClick={() => {
                            setEditData(e);
                            setAddModal(true);
                          }}
                          title={t("edit")}
                        >
                          ✏️
                        </button>
                        <button
                          className="btn btn-ghost p-2 text-sm"
                          onClick={() => setDeleteId(e._id)}
                          title={t("delete")}
                        >
                          🗑️
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <ExpenseModal
        isOpen={addModal}
        onClose={() => {
          setAddModal(false);
          setEditData(null);
        }}
        editData={editData}
        onSuccess={loadExpenses}
      />
      <DeleteModal
        isOpen={!!deleteId}
        onClose={() => setDeleteId(null)}
        onConfirm={handleDelete}
        loading={deleting}
      />
    </div>
  );
}
